"use client";

import Link from "next/link";
import { useMemo, useRef, useState } from "react";
import type { SubscriptionPlan } from "@/lib/api";
import { buyerApi, type PlanCheckoutResponse, type SubscribeResponse } from "@/lib/buyer-api";
import { orderToken } from "@/lib/order-token";
import { subscriptionToken } from "@/lib/subscription-token";
import { PickupCodeCard } from "@/components/pickup-code-card";
import { useToast } from "@/components/toast";
import { cadenceLabel, formatMoney, friendlyErrorMessage } from "@/lib/ui";
import { AuthorizeCard, isStripeAvailable } from "@/components/stripe-card-auth";
import { ErrorAlert } from "@/components/error-alert";

export function SubscribeForm({ plan }: { plan: SubscriptionPlan }) {
  const { showToast } = useToast();
  const [email, setEmail] = useState("");
  const [name, setName] = useState("");
  const [phone, setPhone] = useState("");
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [done, setDone] = useState<SubscribeResponse | null>(null);
  const [checkout, setCheckout] = useState<PlanCheckoutResponse | null>(null);
  const startingCheckoutRef = useRef(false);

  const paymentsReady = Boolean(process.env.NEXT_PUBLIC_STRIPE_PUBLISHABLE_KEY);
  const formLocked = !!checkout;
  const priceSubtotal = checkout?.subtotal_cents ?? plan.price_cents;
  const priceFee = checkout?.buyer_fee_cents ?? 0;
  const priceTotal = checkout?.total_cents ?? plan.price_cents;
  const depositCents = checkout?.deposit_cents ?? plan.deposit_cents ?? 0;
  const feeBps = checkout?.buyer_fee_bps ?? null;
  const feeFlat = checkout?.buyer_fee_flat_cents ?? null;
  const feeLabel = (() => {
    const parts: string[] = [];
    if (feeBps !== null && feeBps > 0) parts.push(`${(feeBps / 100).toFixed(0)}%`);
    if (feeFlat !== null && feeFlat > 0) parts.push(formatMoney(feeFlat));
    return parts.length > 0 ? parts.join(" + ") : null;
  })();

  const nextLabel = useMemo(() => {
    const tz = plan.pickup_location.timezone || "UTC";
    const start = new Date(plan.next_start_at);
    return new Intl.DateTimeFormat("en-US", {
      timeZone: tz,
      weekday: "short",
      month: "short",
      day: "numeric",
      hour: "numeric",
      minute: "2-digit",
    }).format(start);
  }, [plan.next_start_at, plan.pickup_location.timezone]);

  async function startCheckout() {
    if (startingCheckoutRef.current) return;
    if (!isStripeAvailable()) {
      setError("Payment system could not load. Please disable ad blockers and refresh.");
      return;
    }
    startingCheckoutRef.current = true;
    setSubmitting(true);
    setError(null);
    try {
      const res = await buyerApi.checkoutPlan(plan.id, {
        buyer: {
          email,
          name: name || null,
          phone: phone || null,
        },
      });
      setCheckout(res);
      showToast({
        kind: "success",
        message:
          res.mode === "payment_intent"
            ? "Card authorization started."
            : "Card setup started.",
      });
    } catch (e: unknown) {
      setError(friendlyErrorMessage(e));
    } finally {
      setSubmitting(false);
      startingCheckoutRef.current = false;
    }
  }

  async function completeSubscribe() {
    if (!checkout) return;
    try {
      const res = await buyerApi.subscribeToPlan(plan.id, {
        payment_intent_id: checkout.mode === "payment_intent" ? checkout.id : undefined,
        setup_intent_id: checkout.mode === "setup_intent" ? checkout.id : undefined,
        buyer: {
          email,
          name: name || null,
          phone: phone || null,
        },
      });
      subscriptionToken.set(res.subscription.id, res.subscription.buyer_token);
      orderToken.set(res.first_order.id, res.first_order.buyer_token);
      setDone(res);
      setCheckout(null);
      showToast({ kind: "success", message: "Subscription started." });
    } catch {
      // Card is already authorized — keep checkout state so user can retry
      // without re-authorizing their card.
      setError(
        "Your card was authorized, but we couldn\u2019t create your subscription. " +
        "Please tap \u201cAuthorize card\u201d again to retry. " +
        "If the problem persists, contact support \u2014 your card will not be charged.",
      );
      // Re-throw with sentinel so AuthorizeCard resets submitting without
      // overwriting our detailed error message.
      throw new Error("__handled__");
    }
  }

  function handleSubscribeSubmit(e: React.FormEvent) {
    e.preventDefault();
    startCheckout();
  }

  if (done) {
    const order = done.first_order;
    const accessUrl = `/orders/${order.id}?t=${encodeURIComponent(order.buyer_token)}`;
    const subUrl = `/subscriptions/${done.subscription.id}?t=${encodeURIComponent(
      done.subscription.buyer_token,
    )}`;
    return (
      <div className="grid gap-4">
        <section className="lr-card lr-card-strong p-6">
          <h2 className="text-xl font-semibold text-[color:var(--lr-ink)]">
            You&apos;re in!
          </h2>
          <p className="mt-1 text-sm text-[color:var(--lr-muted)]">
            Welcome to {plan.title}
          </p>
          <p className="mt-2 text-sm text-[color:var(--lr-muted)]">
            First order is ready to manage:
          </p>
          <div className="mt-3 flex flex-wrap gap-2">
            <Link
              className="lr-btn lr-btn-primary px-4 py-2 text-sm font-semibold"
              href={accessUrl}
            >
              View first order
            </Link>
            <Link
              className="lr-btn px-4 py-2 text-sm font-semibold text-[color:var(--lr-ink)]"
              href={subUrl}
            >
              Manage subscription
            </Link>
            <Link
              className="lr-btn lr-chip px-4 py-2 text-sm font-semibold text-[color:var(--lr-ink)]"
              href={`/stores/${plan.store_id}/boxes`}
            >
              Back to boxes
            </Link>
          </div>
          <div className="mt-4 rounded-xl bg-white/60 p-4 text-sm text-[color:var(--lr-muted)] ring-1 ring-[color:var(--lr-border)]">
            Payment: your card is on file. If this pickup is within 7 days, it should already be authorized. We capture when pickup is confirmed.
          </div>
        </section>

        <div className="rounded-2xl bg-green-50/50 p-4 ring-1 ring-green-200/50">
          <PickupCodeCard
            storeId={order.store_id}
            orderId={order.id}
            pickupCode={order.pickup_code}
            status={order.status}
          />
        </div>
      </div>
    );
  }

  return (
    <section className="lr-card lr-card-strong p-6">
      <div className="flex flex-wrap items-start justify-between gap-4">
        <div>
          <h2 className="text-base font-semibold text-[color:var(--lr-ink)]">
            Subscribe
          </h2>
          <p className="mt-1 text-sm text-[color:var(--lr-muted)]">
            {cadenceLabel(plan.cadence)} &middot; {formatMoney(plan.price_cents)} per box
          </p>
          <div className="mt-3 text-sm text-[color:var(--lr-muted)]">
            Next pickup:{" "}
            <span className="font-semibold text-[color:var(--lr-ink)]">
              {nextLabel}
            </span>
          </div>
        </div>
      </div>

      <div className="mt-4 rounded-xl bg-white/60 p-4 text-sm ring-1 ring-[color:var(--lr-border)]">
        <div className="grid gap-2">
          <div className="flex items-baseline justify-between gap-4">
            <span className="font-medium text-[color:var(--lr-muted)]">Box</span>
            <span className="font-semibold text-[color:var(--lr-ink)]">
              {formatMoney(priceSubtotal)}
            </span>
          </div>
          <div className="flex items-baseline justify-between gap-4">
            <span className="font-medium text-[color:var(--lr-muted)]">
              Service fee{feeLabel ? ` (${feeLabel})` : ""}
            </span>
            <span className="font-semibold text-[color:var(--lr-ink)]">
              {checkout ? formatMoney(priceFee) : "Calculated at checkout"}
            </span>
          </div>
          {depositCents > 0 ? (
            <div className="flex items-baseline justify-between gap-4">
              <span className="font-medium text-[color:var(--lr-muted)]">
                Refundable deposit
              </span>
              <span className="font-semibold text-[color:var(--lr-ink)]">
                {formatMoney(depositCents)}
              </span>
            </div>
          ) : null}
          <div className="h-px bg-[color:var(--lr-border)]/70" />
          <div className="flex items-baseline justify-between gap-4">
            <span className="font-semibold text-[color:var(--lr-ink)]">
              Total
            </span>
            <span className="font-semibold text-[color:var(--lr-ink)]">
              {checkout ? formatMoney(priceTotal) : `${formatMoney(priceTotal)} + fee`}
            </span>
          </div>
        </div>
      </div>

      {error ? <ErrorAlert error={error} className="mt-4" /> : null}

      {!plan.is_live ? (
        <div className="mt-4 rounded-xl bg-amber-50/70 p-4 text-sm text-amber-900 ring-1 ring-amber-200">
          This box is not live yet. Check back soon, or scan the farmstand QR
          once the seller goes live.
        </div>
      ) : null}

      <form onSubmit={handleSubscribeSubmit} className="mt-4 grid gap-3">
        <label className="grid gap-1">
          <span className="text-xs font-semibold text-[color:var(--lr-muted)]">
            Email
          </span>
          <input
            className="lr-field px-3 py-2 text-sm"
            type="email"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            required
            disabled={formLocked}
          />
        </label>
        <div className="grid gap-2 md:grid-cols-2">
          <label className="grid gap-1">
            <span className="text-xs font-semibold text-[color:var(--lr-muted)]">
              Name (optional)
            </span>
            <input
              className="lr-field px-3 py-2 text-sm"
              value={name}
              onChange={(e) => setName(e.target.value)}
              disabled={formLocked}
            />
          </label>
          <label className="grid gap-1">
            <span className="text-xs font-semibold text-[color:var(--lr-muted)]">
              Phone (optional)
            </span>
            <input
              className="lr-field px-3 py-2 text-sm"
              type="tel"
              value={phone}
              onChange={(e) => setPhone(e.target.value)}
              disabled={formLocked}
              placeholder="(555) 555-1234"
            />
          </label>
        </div>

        <button
          type="submit"
          className={`lr-btn lr-btn-primary inline-flex items-center justify-center px-4 py-2 text-sm font-semibold disabled:opacity-50${checkout ? " cursor-not-allowed" : ""}`}
          disabled={submitting || !email.trim() || !plan.is_live || !paymentsReady || !!checkout}
        >
          {!plan.is_live
            ? "Not live yet"
            : !paymentsReady
              ? "Payments unavailable"
              : checkout
                ? "Complete payment below"
                : submitting
                  ? "Starting\u2026"
                  : "Start subscription"}
        </button>
        {checkout ? (
          <AuthorizeCard
            clientSecret={checkout.client_secret}
            submitting={submitting}
            setSubmitting={setSubmitting}
            setError={setError}
            onAuthorized={completeSubscribe}
            mode={checkout.mode}
          />
        ) : (
          <div className="text-xs text-[color:var(--lr-muted)]">
            Cancel/skip/refunds follow the cutoff policy.{" "}
            <Link className="underline" href="/policies">
              Policies
            </Link>
            .
          </div>
        )}
      </form>
    </section>
  );
}

